clc; clear; close all;

%% ==============================
% MODULE 4: MULTI-NODE DASHBOARD
% ===============================

NUM_NODES = 3;
offline_timeout = 5;   % seconds

% Node state
node_status = repmat("UNKNOWN", NUM_NODES, 1);
last_packet_time = -inf(NUM_NODES, 1);

% Event log: [time, node, status]
event_log = strings(0,3);

%% ---------- SIMULATED PACKETS (FROM MODULE 3) ----------
% Each packet has nodeID, time, status

packets = [
    struct('node',1,'time',50,'status',"WARNING")
    struct('node',2,'time',55,'status',"EMERGENCY")
    struct('node',1,'time',60,'status',"EMERGENCY")
    struct('node',3,'time',65,'status',"WARNING")
    struct('node',2,'time',75,'status',"EMERGENCY")
    struct('node',1,'time',95,'status',"OFFLINE")
];

pkt_idx = 1;

%% ---------- FIGURE ----------
figure('Color','w','Position',[100 100 1300 650]); %[output:179dfe78]

% Node panels
node_axes = gobjects(NUM_NODES,1);
for i = 1:NUM_NODES
    node_axes(i) = subplot(2,NUM_NODES,i); %[output:179dfe78]
    axis off;
end

% Network panel
subplot(2,NUM_NODES,NUM_NODES+1); %[output:179dfe78]
axis off; %[output:179dfe78]
hNet = text(0.5,0.6,'','FontSize',14,'HorizontalAlignment','center'); %[output:179dfe78]

% Event log table
subplot(2,NUM_NODES,(NUM_NODES+2):(2*NUM_NODES)); %[output:179dfe78]
hTable = uitable('Units','normalized',... %[output:179dfe78]
    'Position',[0.05 0.05 0.9 0.35],... %[output:179dfe78]
    'ColumnName',{'Time','Node','Status'},... %[output:179dfe78]
    'Data',{}); %[output:179dfe78]

sgtitle('Module 4: Multi-Node Mine Safety Dashboard','FontWeight','bold'); %[output:179dfe78]

%% ---------- MAIN LOOP ----------
for t = 0:120 %[output:group:60b82368]

    % Packet arrival
    if pkt_idx <= length(packets) && packets(pkt_idx).time == t
        pkt = packets(pkt_idx);
        pkt_idx = pkt_idx + 1;

        node_status(pkt.node) = pkt.status;
        last_packet_time(pkt.node) = t;

        event_log(end+1,:) = [string(t), ...
                              "Node " + pkt.node, ...
                              pkt.status];
        hTable.Data = event_log;
    end

    % Offline detection per node
    for n = 1:NUM_NODES
        if t - last_packet_time(n) > offline_timeout
            node_status(n) = "OFFLINE";
        end
    end

    % ---- DRAW NODE PANELS ----
    for n = 1:NUM_NODES
        axes(node_axes(n)); %#ok<LAXES> %[output:179dfe78] %[output:985f2d0b]
        cla; axis off;

        switch node_status(n)
            case "NORMAL"
                col = 'g';
            case "WARNING"
                col = [0.9 0.6 0];
            case "EMERGENCY"
                col = 'r';
            otherwise
                col = [0.5 0.5 0.5];
        end

        rectangle('Position',[0.15 0.3 0.7 0.4],...
                  'FaceColor',col,'Curvature',0.1);
        text(0.5,0.55,"NODE " + n,...
            'HorizontalAlignment','center','FontSize',14,'Color','w');
        text(0.5,0.4,node_status(n),...
            'HorizontalAlignment','center','FontSize',16,...
            'Color','w','FontWeight','bold');
    end

    % ---- NETWORK HEALTH ----
    subplot(2,NUM_NODES,NUM_NODES+1); cla; axis off; %[output:179dfe78]
    text(0.5,0.6,"Active Nodes: " + ...
        sum(node_status ~= "OFFLINE"),...
        'HorizontalAlignment','center','FontSize',14);

    drawnow;
    pause(0.2);
end %[output:group:60b82368]


